long long  mini(long long a, long long b, long long c)
{

 return a<=b?a<=c?a:c : b<=c?b:c;

}

int main(void)
{


long long min,n,a,b,c;

scanf("%lld%lld%lld%lld",&n,&a,&b,&c);

if(n%4==0)
{
printf("0");
return 0;
}

else if(n%4==3)
{

min = mini(a,b+c,3*c);

}

else if(n%4==2)
{

  min = mini(2*a, b, 2*c);

}

else if(n%4==1)
{

min = mini(3*a, c, a+b);

